long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Sort edges by time in ascending order
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    // Union-Find (Disjoint Set Union) data structure
    vector<long long> parent(n);
    vector<long long> rank(n);

    // Initialize DSU
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
        rank[i] = 1;
    }

    // Function to find the root of a node
    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    // Function to union two nodes
    void unionSet(long long x, long long y) {
        long long rootX = find(x);
        long long rootY = find(y);
        if (rootX != rootY) {
            if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else {
                parent[rootX] = rootY;
                if (rank[rootX] == rank[rootY]) {
                    rank[rootY]++;
                }
            }
        }
    }

    // Count the number of connected components
    long long countComponents() {
        unordered_map<long long, bool> visited;
        long long components = 0;
        for (long long i = 0; i < n; ++i) {
            if (!visited[find(i)]) {
                visited[find(i)] = true;
                components++;
            }
        }
        return components;
    }

    // Process edges in order of increasing time
    long long result = 0;
    for (auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long time = edge[2];

        // Union the nodes
        unionSet(u, v);

        // Check if the number of connected components is at least k
        if (countComponents() >= k) {
            result = time;
            break;
        }
    }

    return result;
}

